import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"碳市场 · 赛道文件","description":"","frontmatter":{"updated":"2026-06-23T00:00:00.000Z","visibility":"public"},"headers":[],"relativePath":"电力新能源/碳市场/赛道文件.md","filePath":"电力新能源/碳市场/赛道文件.md","lastUpdated":1781535932000}'),n={name:"电力新能源/碳市场/赛道文件.md"};function o(h,t,l,s,i,b){return a(),r("div",null,[...t[0]||(t[0]=[e(`<h1 id="碳市场-·-赛道文件" tabindex="-1">碳市场 · 赛道文件 <a class="header-anchor" href="#碳市场-·-赛道文件" aria-label="Permalink to &quot;碳市场 · 赛道文件&quot;">​</a></h1><p><strong>成熟度：</strong> 快速成长期（2026扩围元年） <strong>PE/VC 重心：</strong> 碳管理 SaaS、碳监测 CEMS、碳金融/碳资产、CCER 开发 <strong>数据来源：</strong> China Energy MCP、生态环境部、复旦碳价指数 <strong>数据获取：</strong> 2026-06-15</p><hr><h2 id="一、赛道概览" tabindex="-1">一、赛道概览 <a class="header-anchor" href="#一、赛道概览" aria-label="Permalink to &quot;一、赛道概览&quot;">​</a></h2><h3 id="_1-1-市场规模与增长" tabindex="-1">1.1 市场规模与增长 <a class="header-anchor" href="#_1-1-市场规模与增长" aria-label="Permalink to &quot;1.1 市场规模与增长&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>2024</th><th>2025</th><th>2026E</th><th>2027E</th></tr></thead><tbody><tr><td>覆盖行业</td><td>发电</td><td>发电</td><td>发电+钢铁+水泥+铝冶炼</td><td>扩围至~8,000家企业</td></tr><tr><td>重点排放单位</td><td>~2,200家</td><td>~2,200家</td><td>~3,700家</td><td>~8,000家</td></tr><tr><td>覆盖排放量</td><td>~50亿吨 CO₂</td><td>~50亿吨 CO₂</td><td>~80亿吨 CO₂</td><td>~80亿吨+</td></tr><tr><td>碳价（CEA）</td><td>70-90元/吨</td><td>70-100元/吨</td><td>77-84元/吨（2026.06指数）</td><td>—</td></tr><tr><td>CCER 价格</td><td>—</td><td>—</td><td>78-84元/吨（2026.06指数）</td><td>—</td></tr><tr><td>年交易量</td><td>~3亿吨</td><td>~3.5亿吨</td><td>~5亿吨（预计）</td><td>—</td></tr><tr><td>碳市场总价值</td><td>~250亿</td><td>~300亿</td><td>~400亿+</td><td>—</td></tr></tbody></table><p><strong>核心事件：</strong> 2026年3月，钢铁、水泥、铝冶炼正式纳入全国碳市场，覆盖33%新增排放量。碳价在扩围消息后稳步攀升，从年初~75元/吨升至6月的~80元/吨。</p><blockquote><p>🔗 数据来源：<code>china-energy_search_policy(keyword=&quot;碳市场&quot;)</code>, 复旦碳价指数 2026.06</p></blockquote><h3 id="_1-2-政策时间线" tabindex="-1">1.2 政策时间线 <a class="header-anchor" href="#_1-2-政策时间线" aria-label="Permalink to &quot;1.2 政策时间线&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时间</th><th>事件</th><th>意义</th></tr></thead><tbody><tr><td>2021.07</td><td>全国碳市场上线交易（发电行业）</td><td>启动</td></tr><tr><td>2024.01</td><td>CCER 重启</td><td>自愿减排市场重新开放</td></tr><tr><td>2025.03</td><td>《碳市场扩围方案》发布</td><td>明确钢铁/水泥/铝冶炼纳入路径</td></tr><tr><td>2026.02</td><td>生态环境部2026年碳市场通知</td><td>首次全面部署4大行业履约流程</td></tr><tr><td>2026.03</td><td>钢铁/水泥/铝冶炼正式入市</td><td>扩围首年，分两阶段推进</td></tr><tr><td>2026.10</td><td>2027年度名录公布</td><td>进一步明确边界</td></tr><tr><td>2027+</td><td>深化完善阶段</td><td>配额逐步收紧</td></tr></tbody></table><h3 id="_1-3-分阶段扩围策略" tabindex="-1">1.3 分阶段扩围策略 <a class="header-anchor" href="#_1-3-分阶段扩围策略" aria-label="Permalink to &quot;1.3 分阶段扩围策略&quot;">​</a></h3><p><strong>启动实施阶段（2024-2026年度）：</strong></p><ul><li>以夯实碳排放管理基础、推动企业熟悉市场规则为主要目标</li><li>重点培育市场主体，完善市场监管</li><li>建立激励约束机制</li></ul><p><strong>深化完善阶段（2027年度—）：</strong></p><ul><li>完善政策法规体系，健全监管机制</li><li>建立配额总量逐步适度收紧机制</li><li>推动单位产品碳排放不断下降</li></ul><h3 id="_1-4-后续扩围方向" tabindex="-1">1.4 后续扩围方向 <a class="header-anchor" href="#_1-4-后续扩围方向" aria-label="Permalink to &quot;1.4 后续扩围方向&quot;">​</a></h3><p>已完成 4 大行业（发电/钢铁/水泥/铝冶炼）纳管，下一批预计涉及：</p><ul><li><strong>石化、化工</strong> — 2026年已启动排放报告管理</li><li><strong>建材（平板玻璃）</strong></li><li><strong>有色（铜冶炼）</strong></li><li><strong>造纸</strong></li><li><strong>民航</strong></li></ul><p>这批行业纳管后，全国碳市场将覆盖超过 10,000 家企业。</p><hr><h2 id="二、碳价走势与驱动力" tabindex="-1">二、碳价走势与驱动力 <a class="header-anchor" href="#二、碳价走势与驱动力" aria-label="Permalink to &quot;二、碳价走势与驱动力&quot;">​</a></h2><h3 id="_2-1-碳价驱动因素" tabindex="-1">2.1 碳价驱动因素 <a class="header-anchor" href="#_2-1-碳价驱动因素" aria-label="Permalink to &quot;2.1 碳价驱动因素&quot;">​</a></h3><table tabindex="0"><thead><tr><th>驱动因素</th><th>方向</th><th>强度</th><th>说明</th></tr></thead><tbody><tr><td>扩围新增需求</td><td>↑ 推高</td><td>⭐⭐⭐⭐⭐</td><td>新增1500+企业需要购买配额</td></tr><tr><td>配额收紧趋势</td><td>↑ 推高</td><td>⭐⭐⭐⭐</td><td>2027年后配额逐步收紧</td></tr><tr><td>免费配额占比高</td><td>↓ 抑制</td><td>⭐⭐⭐</td><td>目前仍以免费分配为主</td></tr><tr><td>欧盟 CBAM 传导</td><td>↑ 推高</td><td>⭐⭐⭐</td><td>出口型企业减碳需求增加</td></tr><tr><td>经济周期</td><td>↓ 抑制</td><td>⭐⭐</td><td>工业活动下行→排放减少</td></tr></tbody></table><h3 id="_2-2-中欧碳价对比" tabindex="-1">2.2 中欧碳价对比 <a class="header-anchor" href="#_2-2-中欧碳价对比" aria-label="Permalink to &quot;2.2 中欧碳价对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>中国 CEA</th><th>欧盟 EUA</th></tr></thead><tbody><tr><td>当前价格</td><td><strong>~80元/吨 (~€10/吨)</strong></td><td><strong>~€60-80/吨</strong></td></tr><tr><td>覆盖排放</td><td>~80亿吨</td><td>~15亿吨</td></tr><tr><td>年交易量</td><td>~5亿吨</td><td>~80亿吨</td></tr><tr><td>发展阶段</td><td>启动扩围期</td><td>成熟期（配额拍卖为主）</td></tr><tr><td>金融化程度</td><td>低（仅现货）</td><td>高（期货+期权+衍生品）</td></tr></tbody></table><blockquote><p>💡 中欧碳价差距~6-8x，但中国碳市场体量是欧盟的5倍+。长期看，随着配额收紧和金融化推进，中国碳价有<strong>3-5倍上行空间</strong>。</p></blockquote><hr><h2 id="三、产业链与商业模式" tabindex="-1">三、产业链与商业模式 <a class="header-anchor" href="#三、产业链与商业模式" aria-label="Permalink to &quot;三、产业链与商业模式&quot;">​</a></h2><h3 id="_3-1-碳市场产业链" tabindex="-1">3.1 碳市场产业链 <a class="header-anchor" href="#_3-1-碳市场产业链" aria-label="Permalink to &quot;3.1 碳市场产业链&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>上游（碳排放）         中游（服务/技术）          下游（交易/金融）</span></span>
<span class="line"><span>───────────         ─────────────────         ─────────────────</span></span>
<span class="line"><span> 发电企业             碳管理 SaaS               碳交易所</span></span>
<span class="line"><span> 钢铁企业             碳监测 CEMS              碳资产管理公司</span></span>
<span class="line"><span> 水泥企业             碳核算/核查               CCER 开发商</span></span>
<span class="line"><span> 铝冶炼企业           碳咨询/ESG               碳回购/质押</span></span>
<span class="line"><span> 石化/化工（即将）      碳数据平台               碳指数/数据服务</span></span></code></pre></div><h3 id="_3-2-pe-vc-机会矩阵" tabindex="-1">3.2 PE/VC 机会矩阵 <a class="header-anchor" href="#_3-2-pe-vc-机会矩阵" aria-label="Permalink to &quot;3.2 PE/VC 机会矩阵&quot;">​</a></h3><h4 id="a-碳管理-saas-确定性最高" tabindex="-1">A. 碳管理 SaaS（确定性最高） <a class="header-anchor" href="#a-碳管理-saas-确定性最高" aria-label="Permalink to &quot;A. 碳管理 SaaS（确定性最高）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>公司</th><th>方向</th><th>阶段</th><th>说明</th></tr></thead><tbody><tr><td><strong>碳阻迹</strong></td><td>碳管理 SaaS+咨询</td><td>B轮</td><td>头部碳管理平台</td></tr><tr><td><strong>中创碳投</strong></td><td>碳咨询+数据</td><td>A轮</td><td>政策驱动，企业碳核算</td></tr><tr><td><strong>绿普惠</strong></td><td>碳普惠 C端</td><td>A轮</td><td>个人碳账户模式</td></tr><tr><td><strong>妙盈科技</strong></td><td>ESG+碳数据</td><td>C轮</td><td>金融端碳数据</td></tr><tr><td><strong>诺比节能</strong></td><td>工业碳管理</td><td>B轮</td><td>工业能耗+碳管理</td></tr></tbody></table><p><strong>投资逻辑：</strong></p><ul><li>需求确定性最高——控排企业合规刚需（碳核算/报告/核查）</li><li>盈利模式清晰——SaaS 订阅+项目制</li><li>壁垒——行业数据积累+算法精度</li><li>关注——客户留存率、ARPU 值提升</li></ul><h4 id="b-碳监测-cems-政策强制需求" tabindex="-1">B. 碳监测 CEMS（政策强制需求） <a class="header-anchor" href="#b-碳监测-cems-政策强制需求" aria-label="Permalink to &quot;B. 碳监测 CEMS（政策强制需求）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>公司</th><th>方向</th><th>阶段</th><th>说明</th></tr></thead><tbody><tr><td><strong>雪迪龙</strong></td><td>CEMS 设备</td><td>已上市</td><td>行业龙头</td></tr><tr><td><strong>聚光科技</strong></td><td>环境监测</td><td>已上市</td><td>产品线齐全</td></tr><tr><td><strong>蓝盾光电</strong></td><td>CEMS</td><td>上市公司</td><td>细分市场</td></tr><tr><td><strong>新型传感器初创</strong></td><td>碳监测传感器</td><td>天使-A轮</td><td>技术壁垒高</td></tr></tbody></table><p><strong>投资逻辑：</strong></p><ul><li>碳市场扩围→强制监测需求爆发</li><li>设备销售+运维服务双收入模式</li><li>技术壁垒（精度/稳定性）</li><li>关注：国产替代进展、成本下降曲线</li></ul><h4 id="c-碳金融-碳资产" tabindex="-1">C. 碳金融/碳资产 <a class="header-anchor" href="#c-碳金融-碳资产" aria-label="Permalink to &quot;C. 碳金融/碳资产&quot;">​</a></h4><table tabindex="0"><thead><tr><th>业务模式</th><th>说明</th><th>壁垒</th></tr></thead><tbody><tr><td>碳资产管理</td><td>为控排企业提供配额交易/履约</td><td>资质+经验</td></tr><tr><td>碳回购/质押融资</td><td>碳资产金融化</td><td>金融牌照</td></tr><tr><td>碳指数/数据服务</td><td>碳价预测/碳数据 API</td><td>数据积累+算法</td></tr><tr><td>CCER 开发</td><td>林业碳汇/海上风电/光热</td><td>项目资源+方法学</td></tr></tbody></table><h4 id="d-ccer-方向" tabindex="-1">D. CCER 方向 <a class="header-anchor" href="#d-ccer-方向" aria-label="Permalink to &quot;D. CCER 方向&quot;">​</a></h4><table tabindex="0"><thead><tr><th>方向</th><th>阶段</th><th>说明</th></tr></thead><tbody><tr><td>林业碳汇 CCER</td><td>早期</td><td>首批方法学，大市场规模</td></tr><tr><td>海上风电 CCER</td><td>已有项目</td><td>2024首批方法学</td></tr><tr><td>光热发电 CCER</td><td>早期</td><td>2024首批方法学</td></tr><tr><td>甲烷回收利用</td><td>待方法学发布</td><td>第二批方法学预期</td></tr><tr><td>地质碳封存</td><td>极早期</td><td>技术验证阶段</td></tr></tbody></table><hr><h2 id="四、关键判断" tabindex="-1">四、关键判断 <a class="header-anchor" href="#四、关键判断" aria-label="Permalink to &quot;四、关键判断&quot;">​</a></h2><h3 id="_4-1-投资时机判断" tabindex="-1">4.1 投资时机判断 <a class="header-anchor" href="#_4-1-投资时机判断" aria-label="Permalink to &quot;4.1 投资时机判断&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>投资策略</th><th>关注方向</th></tr></thead><tbody><tr><td><strong>当前 (2026)</strong></td><td>布局早期</td><td>碳管理 SaaS（确定性）、CCER 项目资源（稀缺性）</td></tr><tr><td><strong>2027-2028</strong></td><td>加仓成长期</td><td>碳监测 CEMS 放量、碳资产金融化起步</td></tr><tr><td><strong>2029-2030</strong></td><td>收获期</td><td>碳金融衍生品、碳数据平台、配额交易</td></tr></tbody></table><h3 id="_4-2-关键风险" tabindex="-1">4.2 关键风险 <a class="header-anchor" href="#_4-2-关键风险" aria-label="Permalink to &quot;4.2 关键风险&quot;">​</a></h3><ul><li><strong>政策落地不确定性：</strong> 各省执行力度不一，配额分配松紧直接影响碳价</li><li><strong>碳价波动：</strong> 当前以免费配额为主，碳价信号不够真实</li><li><strong>国际接轨节奏：</strong> CBAM 过渡期至 2026 年，2027 年起正式征税</li><li><strong>地缘政治：</strong> 欧盟可能推迟或修改 CBAM 实施节奏</li></ul><h3 id="_4-3-交叉链接" tabindex="-1">4.3 交叉链接 <a class="header-anchor" href="#_4-3-交叉链接" aria-label="Permalink to &quot;4.3 交叉链接&quot;">​</a></h3><table tabindex="0"><thead><tr><th>关联赛道</th><th>链接</th><th>说明</th></tr></thead><tbody><tr><td><strong>智能电网/VPP</strong></td><td><a href="./../智能电网/新兴赛道">新兴赛道</a></td><td>碳管理+能源管理的交叉</td></tr><tr><td><strong>储能</strong></td><td><a href="./../储能/产业链">产业链</a></td><td>CCER 方法学覆盖储能？</td></tr><tr><td><strong>算电协同</strong></td><td><a href="./../../算电协同/赛道总览">赛道总览</a></td><td>数据中心碳核算是刚需</td></tr><tr><td><strong>AI 应用</strong></td><td><a href="./../../AI/应用层/AI应用赛道">AI应用赛道</a></td><td>AI+碳管理 SaaS</td></tr></tbody></table><hr><p><em>创建：2026-06-15 | 数据来源：生态环境部、复旦碳价指数、China Energy MCP</em></p>`,53)])])}const p=d(n,[["render",o]]);export{g as __pageData,p as default};
